@pagination-prefix-cls: ~'@{ant-prefix}-pagination';

.@{pagination-prefix-cls}-rtl {
  .@{pagination-prefix-cls}-total-text {
    margin-right: 0;
    margin-left: 8px;
  }

  .@{pagination-prefix-cls}-item,
  .@{pagination-prefix-cls}-prev,
  .@{pagination-prefix-cls}-jump-prev,
